 20	  ReplicationType,
 21	} from '@odf/mco/constants';
 22	import { DRClusterAppsMap, ProtectedAppsMap } from '@odf/mco/types';
 23	import {
 24	  getVolumeReplicationHealth,
 25	  ValidateManagedClusterCondition,
 26	} from '@odf/mco/utils';
 27	import {
 28	  GreenCheckCircleIcon,
 29	  YellowExclamationTriangleIcon,
 30	} from '@odf/shared';
 31	import { getMax, getMin } from '@odf/shared/charts';
 32	import HealthItem from '@odf/shared/dashboards/status-card/HealthItem';
 33	import { healthStateMapping } from '@odf/shared/dashboards/status-card/states';
