 37	import { FieldLevelHelp } from '@odf/shared/generic';
 38	import Status, { StatusPopupSection } from '@odf/shared/popup/status-popup';
 39	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 40	import { humanizeDecimalBytesPerSec, humanizeNumber } from '@odf/shared/utils';
 41	import {
 42	  HealthState,
 43	  PrometheusResponse,
 44	  PrometheusResult,
 45	  StatusIconAndText,
 46	  Humanize,
 47	} from '@openshift-console/dynamic-plugin-sdk';
 48	import { UtilizationDurationDropdown } from '@openshift-console/dynamic-plugin-sdk-internal';
 49	import {
 50	  Flex,
 51	  Grid,
 52	  GridItem,
 53	  Text,
 54	  TextVariants,
 55	} from '@patternfly/react-core';
 56	import { ConnectedIcon } from '@patternfly/react-icons';
 57	import { StatusText } from './common';
 58	import './cluster-app-card.scss';
 59	
 60	const checkVolumeReplicationHealth = (
 61	  protectedAppMap: ProtectedAppsMap,
 62	  lastSyncTimeData: PrometheusResponse
 63	): boolean =>
 64	  !!protectedAppMap.placementControlInfo?.find(
 65	    (placementInfo) =>
 66	      !!lastSyncTimeData?.data?.result?.find(
 67	        (item: PrometheusResult) =>
 68	          item.metric?.[OBJECT_NAMESPACE] === placementInfo.drpcNamespace &&
 69	          item.metric?.[OBJECT_NAME] === placementInfo.drpcName &&
 70	          getVolumeReplicationHealth(
 71	            Number(item.value[1]) || 0,
 72	            placementInfo.volumeSyncInterval
 73	          )[0] !== VolumeReplicationHealth.HEALTHY
 74	      )
 75	  );
 76	
 77	const checkKubeObjBackupHealth = (
 78	  protectedAppMap: ProtectedAppsMap
 79	): boolean => {
 80	  const { kubeObjectLastProtectionTime, replicationType } =
 81	    protectedAppMap.placementControlInfo[0];
 82	  const objCaptureInterval =
 83	    protectedAppMap.placementControlInfo[0].kubeObjSyncInterval;
 84	  return protectedAppMap.appType === DRApplication.DISCOVERED &&
 85	    replicationType === ReplicationType.ASYNC
 86	    ? getVolumeReplicationHealth(
 87	        !!kubeObjectLastProtectionTime
 88	          ? getTimeDifferenceInSeconds(kubeObjectLastProtectionTime)
 89	          : LEAST_SECONDS_IN_PROMETHEUS,
 90	        objCaptureInterval
 91	      )[0] !== VolumeReplicationHealth.HEALTHY
 92	    : false;
 93	};
 94	
 95	const OperatorsHealthPopUp: React.FC<OperatorsHealthPopUpProps> = ({
 96	  clusterOperatorStatus,
 97	}) => {
 98	  const { t } = useCustomTranslation();
 99	
100	  return (
101	    <Flex direction={{ default: 'column' }}>
102	      <StatusText>{t('Operator health')}</StatusText>
103	      <Flex data-test="operator-health-description">
104	        {t(
105	          'Operators are responsible for maintaining and reconciling the state of the cluster.'
106	        )}
107	      </Flex>
108	      <Flex>
109	        <StatusPopupSection firstColumn="Operators" secondColumn="Status">
110	          <Status
111	            icon={
112	              healthStateMapping[
113	                clusterOperatorStatus?.[ODR_CLUSTER_OPERATOR] !== '1'
114	                  ? HealthState.ERROR
115	                  : HealthState.OK
116	              ].icon
117	            }
118	            value={
119	              clusterOperatorStatus?.[ODR_CLUSTER_OPERATOR] !== '1'
120	                ? t('Degraded')
121	                : t('Healthy')
122	            }
123	          >
124	            {t('DR Cluster operator')}
125	          </Status>
126	          <Status
127	            icon={
128	              healthStateMapping[
129	                clusterOperatorStatus?.[VOL_SYNC] !== '1'
130	                  ? HealthState.ERROR
131	                  : HealthState.OK
132	              ].icon
133	            }
134	            value={
135	              clusterOperatorStatus?.[VOL_SYNC] !== '1'
136	                ? t('Degraded')
137	                : t('Healthy')
138	            }
139	          >
140	            {t('VolSync')}
141	          </Status>
142	        </StatusPopupSection>
143	      </Flex>
144	    </Flex>
145	  );
146	};
147	
148	export const HealthSection: React.FC<HealthSectionProps> = ({
149	  clusterResources,
150	  csvData,
151	  clusterName,
152	  podData,
153	}) => {
154	  const { t } = useCustomTranslation();
155	
156	  const clusterOperatorStatus = React.useMemo(() => {
157	    const operatorStatus = {};
158	    csvData?.data?.result?.forEach((item: PrometheusResult) => {
159	      if (item?.metric.cluster === clusterName) {
160	        item?.metric.name.startsWith(ODR_CLUSTER_OPERATOR) &&
161	          (operatorStatus[ODR_CLUSTER_OPERATOR] = item?.value[1]);
162	      }
163	    });
164	    podData?.data?.result?.forEach((item: PrometheusResult) => {
165	      if (item?.metric.cluster === clusterName) {
166	        item?.metric.pod.startsWith(VOL_SYNC) &&
167	          (operatorStatus[VOL_SYNC] = item?.value[1]);
168	      }
169	    });
170	    return operatorStatus as ClusterOperatorStatus;
171	  }, [csvData, clusterName, podData]);
172	
173	  return (
174	    <div className="mco-cluster-app__cluster-health-section">
175	      <StatusText>{t('Health')}</StatusText>
176	      <HealthItem
177	        title={t('Cluster health')}
178	        state={
179	          ValidateManagedClusterCondition(
180	            clusterResources[clusterName]?.managedCluster,
181	            MANAGED_CLUSTER_CONDITION_AVAILABLE
182	          )
183	            ? HealthState.OK
184	            : HealthState.ERROR
185	        }
186	      />
187	      <HealthItem
188	        title={t('Operators health')}
189	        // for csv status metrics, '1' means healthy
190	        state={
191	          clusterOperatorStatus?.[ODR_CLUSTER_OPERATOR] !== '1' ||
192	          clusterOperatorStatus?.[VOL_SYNC] !== '1'
193	            ? HealthState.ERROR
194	            : HealthState.OK
195	        }
196	      >
197	        <OperatorsHealthPopUp clusterOperatorStatus={clusterOperatorStatus} />
198	      </HealthItem>
199	    </div>
200	  );
201	};
202	
203	export const PeerConnectionSection: React.FC<PeerConnectionSectionProps> = ({
204	  peerClusters,
205	}) => {
206	  const { t } = useCustomTranslation();
207	  // Exclude the selected cluster
208	  const peerConnectedCount = !!peerClusters.length
209	    ? peerClusters.length - 1
210	    : 0;
211	  return (
212	    <div className="mco-dashboard__contentColumn">
213	      <StatusText>{t('Peer connection')}</StatusText>
214	      <StatusIconAndText
215	        title={t(' {{ peerConnectedCount }} Connected', {
216	          peerConnectedCount,
217	        })}
218	        icon={<ConnectedIcon />}
219	        className="text-muted"
220	      />
221	    </div>
222	  );
223	};
224	
225	const ProtectedAppStatus: React.FC<ProtectedAppStatusProps> = ({
226	  text,
227	  healthyCount,
228	  issueCount,
229	}) => {
230	  return (
231	    <>
232	      <GridItem lg={9} sm={6}>
233	        <Text className="text-muted mco-dashboard__statusText--margin">
234	          {text}
235	        </Text>
236	      </GridItem>
237	      <GridItem lg={2} sm={2}>
238	        <StatusIconAndText
239	          title={healthyCount.toString()}
240	          icon={<GreenCheckCircleIcon />}
241	          className="pf-v6-u-text-align-center"
242	        />
243	      </GridItem>
244	      <GridItem lg={1} sm={4}>
245	        <StatusIconAndText
246	          title={issueCount.toString()}
247	          icon={<YellowExclamationTriangleIcon />}
248	        />
249	      </GridItem>
250	    </>
251	  );
252	};
253	
254	export const ApplicationsSection: React.FC<ApplicationsSectionProps> = ({
255	  clusterResources,
256	  clusterName,
257	  lastSyncTimeData,
258	}) => {
259	  const { t } = useCustomTranslation();
260	
261	  const appsWithIssues = React.useMemo(
262	    () =>
263	      clusterResources[clusterName]?.protectedApps?.reduce(
264	        (acc, protectedAppMap) => {
265	          const hasVolumeReplicationIssue = checkVolumeReplicationHealth(
266	            protectedAppMap,
267	            lastSyncTimeData
268	          );
269	          const hasKubeObjBackupIssue =
270	            checkKubeObjBackupHealth(protectedAppMap);
271	          const hasIssue = hasVolumeReplicationIssue || hasKubeObjBackupIssue;
272	          hasIssue &&
273	            ++acc[protectedAppMap.appType === DRApplication.DISCOVERED ? 0 : 1];
274	          return acc;
275	        },
276	        [0, 0]
277	      ) || [0, 0],
278	    [clusterResources, clusterName, lastSyncTimeData]
279	  );
280	
281	  const protectedAppCount =
282	    clusterResources[clusterName]?.protectedApps?.length;
283	
284	  // All discovered are protected apps
285	  const protectedDiscoveredApps =
286	    clusterResources[clusterName]?.totalDiscoveredAppsCount;
287	  const protectedManagedApps = protectedAppCount - protectedDiscoveredApps;
288	
289	  return (
290	    <div className="mco-dashboard__contentColumn">
291	      <Text component={TextVariants.h1}>{protectedAppCount}</Text>
292	      <StatusText>{t('Protected applications')}</StatusText>
293	      <Grid hasGutter className="pf-v6-u-w-75">
294	        <ProtectedAppStatus
295	          text={t('ACM discovered applications: ')}
296	          healthyCount={protectedDiscoveredApps - appsWithIssues[0]}
297	          issueCount={appsWithIssues[0]}
298	        />
299	        <ProtectedAppStatus
300	          text={t('ACM managed applications: ')}
301	          healthyCount={protectedManagedApps - appsWithIssues[1]}
302	          issueCount={appsWithIssues[1]}
303	        />
304	      </Grid>
305	    </div>
306	  );
307	};
308	
309	const getDescription = (result: PrometheusResult, _index: number) =>
310	  // Returning cluster name as a description
311	  result.metric?.['cluster'] || '';
312	
313	export const SnapshotUtilizationCard: React.FC<
314	  SnapshotUtilizationCardProps
315	> = ({
316	  title,
317	  titleToolTip,
318	  queryType,
319	  humanizeValue,
320	  clusters,
321	  CustomUtilizationSummary,
322	}) => {
323	  return (
324	    <>
325	      <div>
326	        <StatusText>
327	          {title}
328	          {!!titleToolTip && <FieldLevelHelp>{titleToolTip}</FieldLevelHelp>}
329	        </StatusText>
330	      </div>
331	      <PrometheusUtilizationItem
332	        title={''}
333	        utilizationQuery={
334	          !!clusters.length &&
335	          getRBDSnapshotUtilizationQuery(clusters, queryType)
336	        }
337	        humanizeValue={humanizeValue}
338	        basePath={ACM_ENDPOINT}
339	        chartType="grouped-line"
340	        description={getDescription}
341	        hideCurrentHumanized
342	        hideHorizontalBorder
343	        disableGraphLink
344	        showLegend
345	        CustomUtilizationSummary={CustomUtilizationSummary}
346	      />
347	    </>
348	  );
349	};
350	
351	const CustomUtilizationSummary: React.FC<CustomUtilizationSummaryProps> = ({
352	  currentHumanized,
353	  utilizationData,
354	}) => {
355	  const { t } = useCustomTranslation();
356	  const maxVal = getMax(utilizationData);
357	  const minVal = getMin(utilizationData);
358	  const humanizedMax = !!maxVal
359	    ? humanizeDecimalBytesPerSec(maxVal).string
360	    : null;
361	  const humanizedMin = !!minVal
362	    ? humanizeDecimalBytesPerSec(minVal).string
363	    : null;
364	
365	  return (
366	    <div className="co-utilization-card__item-value co-utilization-card__item-summary">
367	      <div>
368	        <span>{t('Current value: ')}</span>
369	        <span className="bold">{currentHumanized}</span>
370	      </div>
371	      {!!utilizationData?.length && (
372	        <>
373	          <div>
374	            <span>{t('Max value: ')}</span>
375	            <span className="bold">{humanizedMax}</span>
376	          </div>
377	          <div>
378	            <span>{t('Min value: ')}</span>
379	            <span className="bold">{humanizedMin}</span>
380	          </div>
381	        </>
382	      )}
383	    </div>
384	  );
385	};
386	
387	export const UtilizationCard: React.FC<UtilizationCardProps> = ({
388	  clusterName,
389	  peerClusters,
390	}) => {
391	  const { t } = useCustomTranslation();
392	
393	  return (
394	    <div className="mco-dashboard__contentColumn">
395	      <div className="mco-dashboard__contentRow mco-cluster-app__contentRow--spaceBetween">
396	        <Text
397	          component={TextVariants.h3}
398	          className="mco-cluster-app__contentRow--flexStart"
399	        >
400	          {t('Utilization')}
401	        </Text>
402	        <div className="mco-dashboard__contentRow mco-cluster-app__contentRow--flexEnd">
403	          <UtilizationDurationDropdown />
404	        </div>
405	      </div>
406	      <div className="mco-cluster-app__graph--margin-bottom">
407	        <SnapshotUtilizationCard
408	          clusters={peerClusters}
409	          title={t('Block volumes snapshots synced')}
410	          queryType={DRDashboard.RBD_SNAPSHOT_SNAPSHOTS}
411	          titleToolTip={t(
412	            'The graph displays the total number of block volumes inbound snapshots, by cluster, from all ApplicationSet and Subscription type applications. Applications that use file volumes are excluded in the total snapshot count.'
413	          )}
414	          humanizeValue={humanizeNumber}
415	        />
416	      </div>
417	      <div className="mco-cluster-app__graph--margin-bottom">
418	        <SnapshotUtilizationCard
419	          clusters={[clusterName]}
420	          title={t('Block volumes replication throughput')}
421	          queryType={DRDashboard.RBD_SNAPSHOTS_SYNC_BYTES}
422	          humanizeValue={humanizeDecimalBytesPerSec}
423	          titleToolTip={t(
424	            'The graph displays the average replication throughput inbound, by cluster, from all ApplicationSet and Subscription type applications. Applications that use file volumes are excluded in the replication throughput.'
425	          )}
426	          CustomUtilizationSummary={CustomUtilizationSummary}
427	        />
428	      </div>
429	    </div>
430	  );
431	};
432	
433	type ClusterOperatorStatus = {
434	  [ODR_CLUSTER_OPERATOR]: string;
435	  [VOL_SYNC]: string;
436	};
437	
438	type OperatorsHealthPopUpProps = {
439	  clusterOperatorStatus: ClusterOperatorStatus;
440	};
441	
442	type HealthSectionProps = {
443	  clusterResources: DRClusterAppsMap;
444	  csvData: PrometheusResponse;
445	  clusterName: string;
446	  podData: PrometheusResponse;
447	};
448	
449	type PeerConnectionSectionProps = {
450	  peerClusters: string[];
451	};
452	
453	type ApplicationsSectionProps = {
454	  clusterResources: DRClusterAppsMap;
455	  clusterName: string;
456	  lastSyncTimeData: PrometheusResponse;
457	};
458	
459	type SnapshotUtilizationCardProps = {
460	  title: string;
461	  queryType: DRDashboard;
462	  humanizeValue: Humanize;
463	  chartLabel?: string;
464	  clusters?: string[];
465	  titleToolTip: JSX.Element;
466	  CustomUtilizationSummary?: React.FC<CustomUtilizationSummaryProps>;
467	};
468	
469	type UtilizationCardProps = {
470	  clusterName: string;
471	  peerClusters: string[];
472	};
473	
474	type ProtectedAppStatusProps = {
475	  text: string;
476	  healthyCount: number;
477	  issueCount: number;
478	};

