254	export const ApplicationsSection: React.FC<ApplicationsSectionProps> = ({
255	  clusterResources,
256	  clusterName,
257	  lastSyncTimeData,
258	}) => {
259	  const { t } = useCustomTranslation();
260	
261	  const appsWithIssues = React.useMemo(
262	    () =>
263	      clusterResources[clusterName]?.protectedApps?.reduce(
264	        (acc, protectedAppMap) => {
265	          const hasVolumeReplicationIssue = checkVolumeReplicationHealth(
266	            protectedAppMap,
267	            lastSyncTimeData
268	          );
269	          const hasKubeObjBackupIssue =
270	            checkKubeObjBackupHealth(protectedAppMap);
271	          const hasIssue = hasVolumeReplicationIssue || hasKubeObjBackupIssue;
272	          hasIssue &&
273	            ++acc[protectedAppMap.appType === DRApplication.DISCOVERED ? 0 : 1];
274	          return acc;
275	        },
276	        [0, 0]
277	      ) || [0, 0],
278	    [clusterResources, clusterName, lastSyncTimeData]
279	  );
280	
281	  const protectedAppCount =
282	    clusterResources[clusterName]?.protectedApps?.length;
283	
284	  // All discovered are protected apps
285	  const protectedDiscoveredApps =
286	    clusterResources[clusterName]?.totalDiscoveredAppsCount;
287	  const protectedManagedApps = protectedAppCount - protectedDiscoveredApps;
288	
289	  return (
290	    <div className="mco-dashboard__contentColumn">
291	      <Text component={TextVariants.h1}>{protectedAppCount}</Text>
292	      <StatusText>{t('Protected applications')}</StatusText>
293	      <Grid hasGutter className="pf-v6-u-w-75">
294	        <ProtectedAppStatus
295	          text={t('ACM discovered applications: ')}
296	          healthyCount={protectedDiscoveredApps - appsWithIssues[0]}
297	          issueCount={appsWithIssues[0]}
298	        />
299	        <ProtectedAppStatus
300	          text={t('ACM managed applications: ')}
301	          healthyCount={protectedManagedApps - appsWithIssues[1]}
302	          issueCount={appsWithIssues[1]}
303	        />
304	      </Grid>
305	    </div>
306	  );
307	};
